    function Neuron(x, y) {
        this.x = x;
        this.y = y;
        this.radius = Math.random() * 8 + 4; // "mountainous"
        this.pulse = 0;
    }

    Neuron.prototype.draw = function(ctx) {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.radius + Math.sin(this.pulse) * 2, 0, Math.PI * 2);
        ctx.fillStyle = "rgba(255, 107, 107, 0.8)";
        ctx.shadowBlur = 20;
        ctx.shadowColor = "#ff6b6b";
        ctx.fill();
    };

    function Synapse(a, b) {
        this.a = a;
        this.b = b;
        this.strength = Math.random() * 0.5 + 0.5;
    }

    Synapse.prototype.draw = function(ctx) {
        ctx.beginPath();
        ctx.moveTo(this.a.x, this.a.y);
        ctx.lineTo(this.b.x, this.b.y);
        ctx.strokeStyle = `rgba(255,217,61,${this.strength})`;
        ctx.lineWidth = 2;
        ctx.shadowBlur = 15;
        ctx.shadowColor = "#ffd93d";
        ctx.stroke();
    };

    function initBrain(canvas) {
        // Create neurons
        for (let i = 0; i < 40; i++) {
            neurons.push(new Neuron(Math.random() * canvas.width, Math.random() * canvas.height));
        }
        // Connect neurons randomly
        for (let i = 0; i < neurons.length; i++) {
            for (let j = i + 1; j < neurons.length; j++) {
                if (Math.random() < 0.05) {
                    synapses.push(new Synapse(neurons[i], neurons[j]));
                }
            }
        }
    }

    function animateBrain(ctx) {
        // Draw synapses
        synapses.forEach(s => s.draw(ctx));

        // Draw neurons
        neurons.forEach(n => {
            n.pulse += 0.05;
            n.draw(ctx);
        });
    }

    // ----------------------------
    // 🔹 Canvas Init (merge both)
    // ----------------------------
    function init() {
        const canvas = document.createElement('canvas');
        container.appendChild(canvas);
        const ctx = canvas.getContext('2d');

        function resizeCanvas() {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        }
        resizeCanvas();

        // Mouse + touch particles
        canvas.addEventListener('mousemove', createParticles);
        canvas.addEventListener('touchmove', (e) => {
            e.preventDefault();
            createParticles(e);
        });

        window.addEventListener('resize', resizeCanvas);

        // Start brain network
        initBrain(canvas);

        // Unified animation loop
        function animate() {
            ctx.fillStyle = "rgba(0,0,0,0.25)";
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            animateBrain(ctx);     // neurons + synapses
            animateParticles(ctx); // glowing particles

            requestAnimationFrame(animate);
        }
        animate();
    }

    init();

    // ----------------------------
    // 🔹 Mobile Navigation (keep as-is)
    // ----------------------------
    const navToggle = document.querySelector('.nav-toggle');
    const navMenu = document.querySelector('.nav-menu');

    navToggle.addEventListener('click', () => {
        navToggle.classList.toggle('active');
        navMenu.classList.toggle('active');
    });

    document.querySelectorAll('.nav-menu a').forEach(link => {
        link.addEventListener('click', () => {
            navToggle.classList.remove('active');
            navMenu.classList.remove('active');
        });
    });

    document.addEventListener('click', (e) => {
        if (!navToggle.contains(e.target) && !navMenu.contains(e.target)) {
            navToggle.classList.remove('active');
            navMenu.classList.remove('active');
        }
    });
</script>
